<?php
 namespace League\CommonMark\Input; use League\CommonMark\Exception\UnexpectedEncodingException; final class MarkdownInput implements MarkdownInputInterface { private $lines; private $content; private $lineCount; public function __construct(string $content) { if (!\mb_check_encoding($content, 'UTF-8')) { throw new UnexpectedEncodingException('Unexpected encoding - UTF-8 or ASCII was expected'); } $this->content = $content; } public function getContent(): string { return $this->content; } public function getLines(): \Traversable { $this->splitLinesIfNeeded(); foreach ($this->lines as $lineNumber => $line) { yield $lineNumber => $line; } } public function getLineCount(): int { $this->splitLinesIfNeeded(); return $this->lineCount; } private function splitLinesIfNeeded(): void { if ($this->lines !== null) { return; } $lines = \preg_split('/\r\n|\n|\r/', $this->content); if ($lines === false) { throw new UnexpectedEncodingException('Failed to split Markdown content by line'); } $this->lines = $lines; if (\end($this->lines) === '') { \array_pop($this->lines); } $this->lineCount = \count($this->lines); } } 